import { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { RealtimeChannel } from '@supabase/supabase-js';
import { supabase } from '../lib/supabase';
import { useAuth } from '../context/AuthContext';
import styles from './Game.module.css';

type WireCard = {
  _color?: number;
  _value?: number;
  color?: number;
  value?: number;
};

type TablePlayer = {
  id?: string;
  name?: string;
  has_cards: boolean;
  chips: number;
  bet: number;
  cards?: WireCard[];
};

type TableState = {
  id: number;
  common_cards: WireCard[];
  players: (TablePlayer | null)[];
  pot: number[];
  button: number;
  playerToPlay: number | null;
  BB: number;
  SB: number;
  game_status: string;
};

type PlayerAction = 'FOLD' | 'CHECK' | 'CALL' | 'RAISE';

const SEATS = [
  styles.seatLeft,
  styles.seatTopLeft,
  styles.seatTop,
  styles.seatTopRight,
  styles.seatRight,
  styles.seatBottom,
];

const RAISE_PRESETS = [20, 33, 50, 75, 100, 150, 200];

function formatCard(card: WireCard | undefined) {
  if (!card) return '?';

  const value = card._value ?? card.value;
  const color = card._color ?? card.color;
  const valueLabel = value === 1 ? 'A' : value === 13 ? 'K' : value === 12 ? 'Q' : value === 11 ? 'J' : String(value ?? '?');
  const suit = color === 0 ? '♠' : color === 1 ? '♥' : color === 2 ? '♦' : '♣';

  return `${valueLabel}${suit}`;
}

function isRedCard(card: WireCard | undefined) {
  const color = card?._color ?? card?.color;
  return color === 1 || color === 2;
}

function formatStack(player: TablePlayer | null | undefined, bigBlind: number | undefined) {
  if (!player) return '';
  if (!bigBlind) return `${player.chips} jetons`;
  const stack = player.chips / bigBlind;
  return `${Number.isInteger(stack) ? stack : stack.toFixed(1)}BB`;
}

function getUserDisplayName(user: { user_metadata?: Record<string, unknown>; email?: string } | null | undefined) {
  const metadata = user?.user_metadata ?? {};
  const name = metadata.username ?? metadata.pseudo ?? metadata.name;
  return typeof name === 'string' && name.trim() ? name : user?.email?.split('@')[0] ?? 'Toi';
}

function extractLatestTableState(rawState: unknown): TableState | null {
  if (!rawState || typeof rawState !== 'object') return null;

  const state = rawState as Record<string, Array<{ payload?: unknown }>>;
  let latest: TableState | null = null;

  for (const presences of Object.values(state)) {
    if (!Array.isArray(presences)) continue;
    for (const presence of presences) {
      const payload = presence?.payload as Partial<TableState> | undefined;
      if (payload && typeof payload.id === 'number' && Array.isArray(payload.players)) {
        latest = payload as TableState;
      }
    }
  }

  return latest;
}

export default function Game() {
  const navigate = useNavigate();
  const { tableId } = useParams();
  const { user, loading: authLoading } = useAuth();

  const [table, setTable] = useState<TableState | null>(null);
  const [privateCards, setPrivateCards] = useState<WireCard[]>([]);
  const [readyForAction, setReadyForAction] = useState(false);
  const [raiseTo, setRaiseTo] = useState('');
  const [feedback, setFeedback] = useState('Connexion à la table...');
  const [selectedAction, setSelectedAction] = useState<PlayerAction | null>(null);
  const [actionChannel, setActionChannel] = useState<RealtimeChannel | null>(null);

  const numericTableId = Number(tableId);
  const potTotal = useMemo(() => table?.pot.reduce((sum, value) => sum + value, 0) ?? 0, [table]);
  const heroSeatIndex = useMemo(() => table?.players.findIndex(player => player?.id === user?.id) ?? -1, [table, user]);
  const isHeroTurn = Boolean(table && heroSeatIndex >= 0 && table.playerToPlay === heroSeatIndex);
  const visiblePlayers = useMemo(() => {
    const players = table?.players ?? [];
    const filled = players.filter(Boolean) as TablePlayer[];
    const hero = filled.find(player => player.id === user?.id) ?? (heroSeatIndex >= 0 ? table?.players[heroSeatIndex] ?? null : null);
    const opponents = filled.filter(player => player.id !== user?.id).slice(0, 5);
    return {
      opponents,
      hero,
    };
  }, [heroSeatIndex, table, user?.id]);

  useEffect(() => {
    if (authLoading) return;
    if (!user) {
      navigate('/');
      return;
    }
    if (!Number.isFinite(numericTableId)) {
      setFeedback('Table introuvable.');
      return;
    }

    let mounted = true;
    const channels: RealtimeChannel[] = [];

    const setup = async () => {
      setFeedback('Connexion à la table...');

      const { data: { session } } = await supabase.auth.getSession();
      if (!session?.access_token) {
        navigate('/login');
        return;
      }

      supabase.realtime.setAuth(session.access_token);

      const privateChannel = supabase.channel(`table:${numericTableId}:private-user:${user.id}`, {
        config: { private: true },
      });
      channels.push(privateChannel);

      privateChannel
        .on('broadcast', { event: 'info' }, ({ payload }) => {
          const card = (payload as { card?: WireCard } | undefined)?.card;
          if (!card) return;
          setPrivateCards(current => current.length >= 2 ? [card] : [...current, card]);
        })
        .on('broadcast', { event: 'ready' }, () => {
          setReadyForAction(true);
          setFeedback('À toi de jouer.');
        });

      const tableActionChannel = supabase.channel(`table:${numericTableId}:action-user:${user.id}`);
      channels.push(tableActionChannel);
      setActionChannel(tableActionChannel);

      tableActionChannel.on('broadcast', { event: 'ready' }, () => {
        setReadyForAction(true);
        setFeedback('À toi de jouer.');
      });

      const tableStateChannel = supabase.channel(`table:${numericTableId}:state`, {
        config: { private: true },
      });
      channels.push(tableStateChannel);

      tableStateChannel
        .on('broadcast', { event: 'state' }, ({ payload }) => {
          if (!mounted || !payload || typeof payload !== 'object') return;
          const next = payload as TableState;
          if (typeof next.id === 'number' && Array.isArray(next.players)) {
            setTable(next);
            setFeedback('');
          }
        })
        .on('presence', { event: 'sync' }, () => {
          const latest = extractLatestTableState(tableStateChannel.presenceState());
          if (latest && mounted) {
            setTable(latest);
            setFeedback('');
          }
        });

      for (const channel of channels) {
        channel.subscribe((status) => {
          if (status === 'SUBSCRIBED' && channel === tableStateChannel) {
            void tableStateChannel.send({
              type: 'broadcast',
              event: 'snapshot_request',
              payload: {
                playerId: user.id,
              },
            });
          }

          if (status === 'CHANNEL_ERROR' || status === 'TIMED_OUT') {
            setFeedback('Connexion realtime impossible pour cette table.');
          }
        });
      }
    };

    setup();

    return () => {
      mounted = false;
      for (const channel of channels) {
        channel.unsubscribe();
        supabase.removeChannel(channel);
      }
      setActionChannel(null);
    };
  }, [authLoading, navigate, numericTableId, user]);

  const sendAction = async (action: PlayerAction) => {
    if (!user || !actionChannel) return;

    setSelectedAction(action);
    window.setTimeout(() => setSelectedAction(current => current === action ? null : current), 180);

    const payload: Record<string, unknown> = { action, playerId: user.id };
    if (action === 'CALL') payload.amount = 0;
    if (action === 'RAISE') {
      const parsed = Number.parseInt(raiseTo, 10);
      if (!Number.isFinite(parsed) || parsed <= 0) {
        setFeedback('Entre un montant de relance valide.');
        return;
      }
      payload.raiseTo = parsed;
    }

    await actionChannel.send({
      type: 'broadcast',
      event: 'player_action',
      payload,
    });

    setReadyForAction(false);
    setFeedback('Action envoyée.');
  };

  return (
    <div className={styles.page}>
      <button className={`${styles.iconButton} ${styles.homeButton}`} onClick={() => navigate('/tournaments')} aria-label="Retour aux tournois">
        <span />
      </button>
      <button className={`${styles.iconButton} ${styles.lobbyButton}`} onClick={() => navigate('/home')} aria-label="Retour à l'accueil">
        <span />
      </button>

      <main className={styles.arena}>
        <section className={styles.table}>
          <div className={styles.outerRail} />
          <div className={styles.innerFelt}>
            <div className={styles.board}>
              <div className={styles.communityCards}>
                {Array.from({ length: 5 }).map((_, index) => {
                  const card = table?.common_cards[index];
                  return (
                    <div key={index} className={`${styles.card} ${styles.boardCard} ${card ? styles.cardVisible : styles.cardSlot} ${isRedCard(card) ? styles.redCard : ''}`}>
                      {card ? formatCard(card) : ''}
                    </div>
                  );
                })}
              </div>
              {potTotal > 0 && <div className={styles.pot}>Pot {potTotal}</div>}
            </div>
          </div>
        </section>

        {visiblePlayers.opponents.map((player, index) => {
          const tableIndex = table?.players.findIndex(candidate => candidate?.id === player.id) ?? -1;
          return (
            <div
              key={player.id ?? index}
              className={`${styles.player} ${SEATS[index] ?? styles.seatTop} ${table?.playerToPlay === tableIndex ? styles.playerActive : ''}`}
            >
              <div className={styles.avatar}>{(player.name ?? '?').slice(0, 1).toUpperCase()}</div>
              <div className={styles.opponentCards}>
                {[0, 1].map(cardIndex => (
                  <div key={cardIndex} className={`${styles.card} ${styles.smallCard} ${player.cards?.[cardIndex] ? styles.cardVisible : styles.cardBack} ${isRedCard(player.cards?.[cardIndex]) ? styles.redCard : ''}`}>
                    {player.cards?.[cardIndex] ? formatCard(player.cards[cardIndex]) : ''}
                  </div>
                ))}
              </div>
              {player.bet ? <div className={styles.bet}>{player.bet}BB</div> : null}
              <div className={styles.playerName}>{player.name ?? 'Joueur'}</div>
              <div className={styles.playerStack}>{formatStack(player, table?.BB)}</div>
              {table?.button === tableIndex && <div className={styles.dealer}>D</div>}
            </div>
          );
        })}

        <div className={`${styles.player} ${styles.heroPlayer} ${isHeroTurn ? styles.playerActive : ''}`}>
          <div className={styles.heroCards}>
            {[0, 1].map(index => {
              const card = privateCards[index] ?? visiblePlayers.hero?.cards?.[index];
              return (
                <div key={index} className={`${styles.card} ${styles.heroCard} ${card ? styles.cardVisible : styles.cardBack} ${isRedCard(card) ? styles.redCard : ''}`}>
                  {card ? formatCard(card) : ''}
                </div>
              );
            })}
          </div>
          <div className={styles.heroInfo}>
            <div className={styles.playerName}>{visiblePlayers.hero?.name ?? getUserDisplayName(user)}</div>
            <div className={styles.playerStack}>{formatStack(visiblePlayers.hero, table?.BB) || '-'}</div>
          </div>
        </div>

        <section className={styles.controls} aria-label="Actions">
          <div className={styles.presetRow}>
            {RAISE_PRESETS.map(percent => (
              <button key={percent} className={styles.presetBtn} onClick={() => setRaiseTo(String(percent))}>
                {percent}%
              </button>
            ))}
          </div>
          <div className={styles.actionRow}>
            {(['FOLD', 'CHECK', 'RAISE'] as PlayerAction[]).map(action => (
              <button
                key={action}
                className={`${styles.actionBtn} ${selectedAction === action ? styles.actionBtnSelected : ''}`}
                disabled={!readyForAction && !isHeroTurn}
                onClick={() => sendAction(action)}
              >
                {action === 'FOLD' ? 'Fold' : action === 'CHECK' ? 'Check' : 'Raise'}
              </button>
            ))}
            <button
              className={`${styles.actionBtn} ${styles.callBtn} ${selectedAction === 'CALL' ? styles.actionBtnSelected : ''}`}
              disabled={!readyForAction && !isHeroTurn}
              onClick={() => sendAction('CALL')}
            >
              {raiseTo ? `${raiseTo}BB` : 'Call'}
            </button>
          </div>
          <input
            className={styles.raiseInput}
            value={raiseTo}
            onChange={event => setRaiseTo(event.target.value)}
            placeholder="Relance"
            inputMode="numeric"
            aria-label="Montant de relance"
          />
          <p className={styles.feedback}>{feedback || (isHeroTurn ? 'À toi de jouer.' : 'En attente des autres joueurs.')}</p>
        </section>

        <footer className={styles.tableInfo}>
          <span>{table?.game_status ?? 'Connexion'}</span>
          <span>Niveau 1 : {table?.SB ?? '-'}/{table?.BB ?? '-'}</span>
          <strong>BB</strong>
        </footer>
      </main>
    </div>
  );
}
